document.querySelectorAll('.concept-card').forEach(card => {
    // GATE: tabindex="0" inserts card into natural tab order
    card.setAttribute('tabindex', '0');
    // GATE: Enter key fires same action as click for keyboard users
    card.addEventListener('keypress', (e) => {
        if (e.key === 'Enter') card.click();
    });
});

// GATE: Performance heartbeat — must not block main thread itself
// GATE: Interval of 5000ms chosen to avoid adding measurement overhead
setInterval(() => {
    const start = performance.now();
    setTimeout(() => {
        const lag = performance.now() - start;
        // GATE: 50ms threshold — exceeding it indicates a jank frame
        // Source: RAIL model — https://web.dev/articles/rail
        if (lag > 50) {
            console.warn(`GATE: Main-thread lag detected: ${lag.toFixed(1)}ms`);
        }
    }, 0);
}, 5000);

// GATE: Scroll throttle state — must persist across rAF loop iterations
let _lastScrollTime = 0;
const SCROLL_THROTTLE_MS = 250;

// GATE: Called inside syncClockLoop() after active token is identified
function syncTranscriptScroll(activeToken) {
    const now = performance.now();
    // GATE: Throttle to SCROLL_THROTTLE_MS — prevents scroll jitter on fast loops
    if (now - _lastScrollTime < SCROLL_THROTTLE_MS) return;
    _lastScrollTime = now;

    const container = document.getElementById('transcript-container');
    if (!container || !activeToken) return;

    // GATE: Center active token vertically in container
    // offsetTop relative to container, minus half container height
    // Source: CSSOM View Module — https://drafts.csswg.org/cssom-view/#dom-element-scrollintoview
    const tokenTop = activeToken.offsetTop;
    const containerHeight = container.clientHeight;
    const targetScrollTop = tokenTop - (containerHeight / 2) + (activeToken.offsetHeight / 2);

    // GATE: smooth behavior — avoids jarring snap during continuous playback
    container.scrollTo({ top: targetScrollTop, behavior: 'smooth' });
}
// CSS addition: #transcript-container { scroll-padding-top: 40%; scroll-padding-bottom: 40%; }
